{
  "summary": "A procedural 5-pointed star sparkle effect featuring a bright core and a soft radial glow. The effect uses a generated texture to avoid external assets, animating with a quick 'pop' scale and a gentle rotation fade-out.",
  "duration_ms": 700,
  "palette": [
    "#FFFFFF",
    "#FFF9C4",
    "#FFD54F"
  ],
  "particle_config": {
    "count": 1,
    "scale": {
      "start": 0,
      "end": 1.2,
      "ease": "Back.easeOut"
    },
    "alpha": {
      "start": 1,
      "end": 0,
      "ease": "Cubic.easeIn"
    },
    "rotation": {
      "start": 0,
      "end": 45
    },
    "blendMode": "ADD",
    "lifespan": 700
  },
  "typescript": "class SparkleEffect {
  static createStarTexture(scene: Phaser.Scene, key: string = 'sparkle_star') {
    if (scene.textures.exists(key)) return;
    const size = 64;
    const graphics = scene.make.graphics({ x: 0, y: 0, add: false });

    // Outer Glow
    graphics.fillStyle(0xFFD54F, 0.3);
    graphics.fillCircle(size / 2, size / 2, size / 2.5);

    // Star Shape
    graphics.fillStyle(0xFFFFFF, 1);
    const points = 5;
    const innerRadius = size / 6;
    const outerRadius = size / 3;
    const centerX = size / 2;
    const centerY = size / 2;

    graphics.beginPath();
    for (let i = 0; i < 2 * points; i++) {
      const r = (i % 2 === 0) ? outerRadius : innerRadius;
      const angle = (Math.PI / points) * i - Math.PI / 2;
      graphics.lineTo(centerX + r * Math.cos(angle), centerY + r * Math.sin(angle));
    }
    graphics.closePath();
    graphics.fillPath();

    graphics.generateTexture(key, size, size);
    graphics.destroy();
  }

  static play(scene: Phaser.Scene, x: number, y: number) {
    this.createStarTexture(scene);
    const emitter = scene.add.particles(x, y, 'sparkle_star', {
      lifespan: 700,
      speed: { min: 10, max: 50 },
      scale: { start: 0.2, end: 1.5, ease: 'Back.Out' },
      alpha: { start: 1, end: 0 },
      rotate: { start: 0, end: 90 },
      blendMode: 'ADD',
      emitting: false
    });

    emitter.explode(1);
    scene.time.delayedCall(800, () => emitter.destroy());
  }
}"
}
}
